+---
+import { Icon } from '@astrojs/starlight/components';
+
+/**
+ * Dropdown component for selecting topics.
+ * Used in the sidebar when a root topic is configured to use dropdown mode.
+ */
+interface Props {
+  items: Array<{
+    label: string;
+    link: string;
+    icon?: string;
+    color?: string;
+    isCurrent: boolean;
+  }>;
+}
+
+const { items } = Astro.props;
+const currentItem = items.find((item) => item.isCurrent) || items[0];
+---
+
+<div class="topic-dropdown">
+  <button
+    type="button"
+    class="topic-dropdown-trigger"
+    aria-expanded="false"
+    aria-haspopup="listbox"
+  >
+    {currentItem?.icon && (
+      <span class="topic-dropdown-trigger-icon" data-color={currentItem.color}>
+        <Icon name={currentItem.icon} />
+      </span>
+    )}
+    <span class="topic-dropdown-label">{currentItem?.label}</span>
+    <svg
+      class="topic-dropdown-chevron"
+      width="20"
+      height="20"
+      viewBox="0 0 24 24"
+      fill="none"
+      stroke="currentColor"
+      stroke-width="2"
+      stroke-linecap="round"
+      stroke-linejoin="round"
+    >
+      <polyline points="6 9 12 15 18 9"></polyline>
+    </svg>
+  </button>
+  <ul class="topic-dropdown-menu" role="listbox" hidden>
+    {items.map((item) => (
+      <li role="option" aria-selected={item.isCurrent ? "true" : "false"}>
+        <a
+          href={item.link}
+          class:list={['topic-dropdown-item', { 'is-current': item.isCurrent }]}
+        >
+          {item.icon && (
+            <span class="topic-dropdown-icon" data-color={item.color}>
+              <Icon name={item.icon} />
+            </span>
+          )}
+          <span>{item.label}</span>
+        </a>
+      </li>
+    ))}
+  </ul>
+</div>
+
+<script>
+  // Handle dropdown toggle
+  document.querySelectorAll('.topic-dropdown').forEach((dropdown) => {
+    const trigger = dropdown.querySelector('.topic-dropdown-trigger');
+    const menu = dropdown.querySelector('.topic-dropdown-menu');
+
+    if (!trigger || !menu) return;
+
+    trigger.addEventListener('click', () => {
+      const isExpanded = trigger.getAttribute('aria-expanded') === 'true';
+      trigger.setAttribute('aria-expanded', String(!isExpanded));
+      menu.hidden = isExpanded;
+    });
+
+    // Close on click outside
+    document.addEventListener('click', (e) => {
+      if (!dropdown.contains(e.target as Node)) {
+        trigger.setAttribute('aria-expanded', 'false');
+        menu.hidden = true;
+      }
+    });
+
+    // Close on escape
+    document.addEventListener('keydown', (e) => {
+      if (e.key === 'Escape') {
+        trigger.setAttribute('aria-expanded', 'false');
+        menu.hidden = true;
+      }
+    });
+  });
+</script>
+
+<style>
